// Generate prospecting job request with vertical scoring config
const weekDate = new Date().toISOString().split('T')[0];

return [{
  json: {
    weekDate,
    idempotencyKey: `sales-prospecting:weekly:${weekDate}`,
    prompt: `Run weekly prospecting cycle for all enabled verticals.\n\n**IMPORTANT**: Read config.json at the runner working directory to get the verticals configuration. Look at the 'verticals' key for enabled vertical profiles and their scoring matrices. Also read the 'salesMarketing' key for MQL thresholds and outreach decay settings.\n\nFor each enabled vertical:\n1. Dispatch sales-researcher to check signal sources defined in the vertical's signalSources config\n2. Apply the scoring matrix from the vertical's scoring.signals config to calculate lead_score for each prospect\n3. Set Status (Hot/Warm/Cold) based on the vertical's scoring.thresholds\n4. Check for prospects crossing the MQL threshold (salesMarketing.mqlThreshold) with a recent signal within the signal window (salesMarketing.mqlSignalWindowDays)\n5. Apply outreach decay for stale sequences (salesMarketing.outreachDecayDays)\n\nUpdate the Sales Pipeline Report in Confluence with scoring distribution by vertical, top un-contacted prospects, and MQL activity.`,
    context: JSON.stringify({
      instruction: "Read config.json verticals section for scoring matrices. Use salesMarketing section for MQL and decay thresholds. Do NOT hardcode scoring values.",
      configPath: "claude-runner/config.json",
      configKeys: ["verticals", "salesMarketing"]
    })
  }
}];

